+/// Map a `Mode` back to the corresponding `Target` variant for content generation.
+/// This is the inverse of `Target::to_mode`.
+fn mode_to_target(mode: Mode) -> Target {
+    match mode {
+        Mode::Mcp => Target::Mcp,
+        Mode::Skill => Target::Skill,
